1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type Customer = { yearsWithMHPCO: number };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { customer: Customer; steps: Step[] };
9	type Policy = { items: Item[]; remainingCap: number };
10	
11	const PROCESSING_FEE = 5;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
15	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
16	
17	const INSURANCE_VALUE: Record<string, number> = {
18	  sword: 1000,
19	  amulet: 600,
20	  staff: 800,
21	  potion: 400,
22	  rune: 250,
23	  moonstone: 250,
24	};
25	
26	const FIRST_INSURANCE_RATE = 0.1;
27	const CURSE_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_THRESHOLD_YEARS = 2;
32	const FOLLOWUP_DISCOUNT_RATE = 0.15;
33	
34	const COMPONENT_BLOCK_SIZE = 3;
35	const COMPONENT_BLOCK_PRICE = 60;
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	const BASE_PREMIUM: Record<string, number> = {
39	  sword: 100,
40	  amulet: 60,
41	  staff: 80,
42	  potion: 40,
43	  rune: 25,
44	  moonstone: 25,
45	};
46	
47	const countBy = <T>(items: T[], keyOf: (item: T) => string): Record<string, number> => {
48	  const counts: Record<string, number> = {};
49	  for (const item of items) counts[keyOf(item)] = (counts[keyOf(item)] ?? 0) + 1;
50	  return counts;
51	};
52	
53	const countByType = (items: Item[]): Record<string, number> =>
54	  countBy(items, (item) => item.type);
55	
56	const qualifiesForComponentBlock = (type: string, count: number): boolean =>
57	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
58	
59	const lineItemPrice = (type: string, count: number): number =>
60	  qualifiesForComponentBlock(type, count)
61	    ? COMPONENT_BLOCK_PRICE
62	    : BASE_PREMIUM[type] * count;
63	
64	const sumBasePremiums = (items: Item[]): number =>
65	  Object.entries(countByType(items))
66	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
67	
68	const rateOf = (amount: number, rate: number, applies: boolean): number =>
69	  applies ? amount * rate : 0;
70	
71	const isCursed = (item: Item): boolean => item.cursed === true;
72	
73	const enchantmentAtLeast = (item: Item, threshold: number): boolean =>
74	  (item.enchantment ?? 0) >= threshold;
75	
76	const isHighlyEnchanted = (item: Item): boolean =>
77	  enchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
78	
79	const itemSurcharges = (items: Item[]): number =>
80	  items.reduce((sum, item) => {
81	    const base = BASE_PREMIUM[item.type];
82	    return sum
83	      + rateOf(base, CURSE_SURCHARGE_RATE, isCursed(item))
84	      + rateOf(base, HIGH_ENCHANTMENT_RATE, isHighlyEnchanted(item));
85	  }, 0);
86	
87	const isLoyalCustomer = (customer: Customer): boolean =>
88	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
89	
90	const isFollowupContract = (stepIndex: number): boolean => stepIndex > 0;
91	
92	const quotePremium = (items: Item[], customer: Customer, stepIndex: number): number => {
93	  const basePremium = sumBasePremiums(items);
94	  const surcharges = itemSurcharges(items);
95	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
96	  const loyaltyDiscount = rateOf(basePremium, LOYALTY_DISCOUNT_RATE, isLoyalCustomer(customer));
97	  const followupDiscount = rateOf(basePremium, FOLLOWUP_DISCOUNT_RATE, isFollowupContract(stepIndex));
98	  return Math.ceil(basePremium + surcharges + firstInsurance - loyaltyDiscount - followupDiscount + PROCESSING_FEE);
99	};
100	
101	const validateItems = (items: Item[]): void => {
102	  for (const item of items) {
103	    if (!(item.type in BASE_PREMIUM)) {
104	      throw new Error(`Unknown item type: ${item.type}`);
105	    }
106	  }
107	};
